import{_ as a,o,c as l,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"39. Allowances Related To Overtime And On Call","description":"","frontmatter":{"title":"39. Allowances Related To Overtime And On Call","eba":"Biomedical Engineers 2025-2028","topics":["hours","overtime","shift-work","rosters"]},"headers":[],"relativePath":"ebas/biomedical-engineers/allowances/39-allowances-related-to-overtime-and-on-call.md","filePath":"ebas/biomedical-engineers/allowances/39-allowances-related-to-overtime-and-on-call.md"}'),t={name:"ebas/biomedical-engineers/allowances/39-allowances-related-to-overtime-and-on-call.md"};function r(s,e,i,p,c,d){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="_39-allowances-related-to-overtime-and-on-call" tabindex="-1">39. Allowances Related To Overtime And On Call <a class="header-anchor" href="#_39-allowances-related-to-overtime-and-on-call" aria-label="Permalink to &quot;39. Allowances Related To Overtime And On Call&quot;">​</a></h1><p><strong>39.1</strong> Meal Allowance</p><p><strong>(a)</strong> An Employee shall either be supplied with a meal or be paid an allowance as specified in subclause 39.1(b) where the Employee works:</p><p><strong>(i)</strong> more than one hour of overtime after the end of a rostered shift; or</p><p><strong>(ii)</strong> more than two hours of overtime when they have been recalled to duty outside of usual working hours and when the time of such recall coincides with or over-runs normal hospital meal times.</p><p><strong>(b)</strong> The meal allowance shall be paid in accordance with the rates set out in Appendix 2.</p><p><strong>39.2</strong> On-call Allowance An Employee rostered to be on-call (pursuant to subclause 44.1) shall be paid the on-call allowance outlined in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> in respect of any 12 hour period or part thereof during which the Employee is on-call.</p><p><strong>39.3</strong> Telephone Allowance</p><p><strong>(a)</strong> Where the Employer requires an Employee to purchase, install and/or maintain a telephone (whether it be a land-line or a mobile phone) for the purposes of being on-call, the Employer will reimburse the purchase or installation costs and the subsequent rental charges or mobile phone charges on production of receipted accounts.</p><p><strong>(b)</strong> In lieu of paying an Employee the telephone allowance, an Employer may provide an Employee with a mobile phone for the purposes of being on-call and pay any costs and charges associated with it.</p><p>MATTERS</p><p>Plain language terms: OT, extra hours, double time.</p>',12)])])}const u=a(t,[["render",r]]);export{m as __pageData,u as default};
